# Install Ollama (macOS/Linux): curl -fsSL https://ollama.com/install.sh | sh
# Then: ollama pull llama3.2:3b   (downloads a Q4_K_M GGUF, ~2 GB)
#        ollama serve              (starts the HTTP API on port 11434)

import httpx, json

# Ollama exposes a /api/chat endpoint compatible with its own SDK
# and a /v1/ OpenAI-compatible prefix as of Ollama 0.1.29+

def chat_ollama(prompt: str, model: str = "llama3.2:3b") -> str:
    """Non-streaming chat call to a local Ollama server."""
    payload = {
        "model": model,
        "messages": [{"role": "user", "content": prompt}],
        "stream": False,
        "options": {
            "temperature": 0.2,
            "num_predict": 200,
        },
    }
    resp = httpx.post("http://localhost:11434/api/chat", json=payload, timeout=120)
    resp.raise_for_status()
    return resp.json()["message"]["content"]


def stream_ollama(prompt: str, model: str = "llama3.2:3b") -> None:
    """Streaming chat — prints tokens as they arrive."""
    payload = {
        "model": model,
        "messages": [{"role": "user", "content": prompt}],
        "stream": True,
    }
    with httpx.stream("POST", "http://localhost:11434/api/chat",
                      json=payload, timeout=120) as resp:
        for line in resp.iter_lines():
            if line:
                data = json.loads(line)
                print(data["message"]["content"], end="", flush=True)
                if data.get("done"):
                    break
    print()


if __name__ == "__main__":
    print(chat_ollama("What is the GGUF file format used for?"))
    stream_ollama("List three benefits of running LLMs locally.")
